import React from "react";
import { BrowserRouter as Router, Routes, Route, Navigate } from "react-router-dom";

import Landing from "./pages/Landing";
import Login from "./pages/Login";
import Register from "./pages/Register";
import OtpVerify from "./pages/OtpVerify";
import ForgotPassword from "./pages/ForgotPassword";
import ResetPassword from "./pages/ResetPassword";
import DashboardLayout from "./pages/Dashboard/DashboardLayout";
import DashboardHome from "./pages/Dashboard/DashboardHome";
import Profit from "./pages/Dashboard/Profit";
import Loss from "./pages/Dashboard/Loss";
import Expense from "./pages/Dashboard/Expense";
import Analytics from "./pages/Dashboard/Analytics";
import Profile from "./pages/Dashboard/Profile";

// Import SideDrawer
import SideDrawer from "./layout/SideDrawer";

const PrivateRoute = ({ children }) => {
  const token = localStorage.getItem("token");
  return token ? children : <Navigate to="/login" />;
};

function App() {
  const token = localStorage.getItem("token");
  const location = window.location.pathname;

  // Pages where SideDrawer should NOT be shown
  const authPages = ["/", "/login", "/register", "/otp-verify", "/forgot-password", "/reset-password"];
  const isAuthPage = authPages.includes(location);

  // Check if on profile page (to conditionally hide sidebar)
  const isProfilePage = location === "/dashboard/profile";

  return (
    <Router>
      {/* 🔥 Show SideDrawer ONLY when:
          1. User is logged in (token exists)
          2. Not on auth pages
          3. Not on profile page (optional - you can remove this if you want sidebar on profile)
      */}
      {token && !isAuthPage && !isProfilePage && <SideDrawer />}

      <Routes>
        {/* Public Routes */}
        <Route path="/" element={<Landing />} />
        <Route path="/login" element={<Login />} />
        <Route path="/register" element={<Register />} />
        <Route path="/otp-verify" element={<OtpVerify />} />
        <Route path="/forgot-password" element={<ForgotPassword />} />
        <Route path="/reset-password" element={<ResetPassword />} />

        {/* Private Routes */}
        <Route
          path="/dashboard"
          element={
            <PrivateRoute>
              <DashboardLayout />
            </PrivateRoute>
          }
        >
          <Route index element={<DashboardHome />} />
          <Route path="profit" element={<Profit />} />
          <Route path="loss" element={<Loss />} />
          <Route path="expense" element={<Expense />} />
          <Route path="analytics" element={<Analytics />} />
          <Route path="profile" element={<Profile />} />
        </Route>

        {/* Catch all - redirect to login if route not found */}
        <Route path="*" element={<Navigate to="/login" />} />
      </Routes>
    </Router>
  );
}

export default App;
